+        let start = std::time::Instant::now();
+        for i in 0..ROW_COUNT {
+            conn.execute(INSERT_SQL, rusqlite::params![i]).unwrap();
+        }
+        let elapsed = start.elapsed();
+        let count: i64 = conn
+            .query_row("SELECT COUNT(*) FROM bench", [], |row| row.get(0))
